func main() {
    stack := []int{}

    // Push
    stack = append(stack, 10)
    stack = append(stack, 20)
    stack = append(stack, 30)

    // Peek
    fmt.Println(stack[len(stack)-1])  // 30

    // Pop
    top := stack[len(stack)-1]
    stack = stack[:len(stack)-1]
    fmt.Println(top)                  // 30
    fmt.Println(stack)                // [10 20]
}

func main() {
    queue := []string{}

    // Enqueue
    queue = append(queue, "first")
    queue = append(queue, "second")
    queue = append(queue, "third")

    // Dequeue
    front := queue[0]
    queue = queue[1:]
    fmt.Println(front)   // first
    fmt.Println(queue)   // [second third]
}

func isValid(s string) bool {
    stack := []rune{}
    pairs := map[rune]rune{')': '(', ']': '[', '}': '{'}
    for _, ch := range s {
        if ch == '(' || ch == '[' || ch == '{' {
            stack = append(stack, ch)
        } else {
            if len(stack) == 0 || stack[len(stack)-1] != pairs[ch] {
                return false
            }
            stack = stack[:len(stack)-1]
        }
    }
    return len(stack) == 0
}

func main() {
    fmt.Println(isValid("()[]{}"))   // true
    fmt.Println(isValid("(]"))       // false
}

