func main() {
    graph := map[int][]int{1: {2, 3}, 2: {4}, 3: {4}, 4: {}}
    queue := []int{1}
    visited := map[int]bool{1: true}
    level := 0

    for len(queue) > 0 {
        size := len(queue)
        fmt.Printf("Level %d: ", level)
        for i := 0; i < size; i++ {
            node := queue[0]
            queue = queue[1:]
            fmt.Printf("%d ", node)
            for _, nb := range graph[node] {
                if !visited[nb] {
                    visited[nb] = true
                    queue = append(queue, nb)
                }
            }
        }
        fmt.Println()
        level++
    }
}

